/**
 * Workflow State Consistency Tests - SKF Module
 *
 * Validates cross-step state consistency for VS, RA, and compose-mode workflows:
 * - VS feasibility report frontmatter fields match step consumption
 * - RA state file comment block format matches step-05 recovery parser
 * - Compose-mode confidence tier labels match compose-mode-rules.md matrix
 *
 * These are static analysis tests against the step markdown files.
 * Usage: node test/test-workflow-state.js
 */

const path = require('node:path');
const fs = require('node:fs/promises');

// ANSI colors
const colors = {
  reset: '\u001B[0m',
  green: '\u001B[32m',
  red: '\u001B[31m',
  yellow: '\u001B[33m',
  cyan: '\u001B[36m',
  dim: '\u001B[2m',
};

let passed = 0;
let failed = 0;

function assert(condition, testName, errorMessage = '') {
  if (condition) {
    console.log(`${colors.green}\u2713${colors.reset} ${testName}`);
    passed++;
  } else {
    console.log(`${colors.red}\u2717${colors.reset} ${testName}`);
    if (errorMessage) {
      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
    }
    failed++;
  }
}

async function readFile(filePath) {
  return fs.readFile(filePath, 'utf8');
}

async function runTests() {
  console.log(`${colors.cyan}========================================`);
  console.log('SKF Workflow State Consistency Tests');
  console.log(`========================================${colors.reset}\n`);

  const projectRoot = path.join(__dirname, '..');
  const srcDir = path.join(projectRoot, 'src');

  // ============================================================
  // Test Suite 1: VS Feasibility Report Frontmatter Fields
  // ============================================================
  console.log(`${colors.yellow}Test Suite 1: VS Frontmatter Field Consistency${colors.reset}\n`);

  const vsTemplate = await readFile(path.join(srcDir, 'skf-verify-stack/assets/feasibility-report-template.md'));
  const vsStep06 = await readFile(path.join(srcDir, 'skf-verify-stack/steps-c/step-06-report.md'));
  const vsStep05 = await readFile(path.join(srcDir, 'skf-verify-stack/steps-c/step-05-synthesize.md'));

  // Extract frontmatter field names from template
  const templateFrontmatter = vsTemplate.split('---')[1];
  const templateFields = new Set(templateFrontmatter.match(/^(\w+):/gm).map((f) => f.replace(':', '')));

  // Key fields that step-06 must read
  const requiredStep06Fields = [
    'skills_analyzed',
    'coverage_percentage',
    'integrations_verified',
    'integrations_plausible',
    'integrations_risky',
    'integrations_blocked',
    'requirements_fulfilled',
    'requirements_partial',
    'requirements_not_addressed',
    'requirements_pass',
    'overall_verdict',
    'recommendation_count',

import js from '@eslint/js';
import eslintConfigPrettier from 'eslint-config-prettier/flat';
import nodePlugin from 'eslint-plugin-n';
import unicorn from 'eslint-plugin-unicorn';
import yml from 'eslint-plugin-yml';

export default [
  // Global ignores for files/folders that should not be linted
  {
    ignores: [
      'dist/**',
      'coverage/**',
      '**/*.min.js',
      'test/template-test-generator/**',
      'test/template-test-generator/**/*.js',
      'test/template-test-generator/**/*.md',
      'test/fixtures/**',
      'test/fixtures/**/*.yaml',
      '_bmad/**',
      '_bmad*/**',
      // Build output
      'build/**',
      // Website uses ESM/Astro - separate linting ecosystem
      'website/**',
      // Gitignored patterns
      'z*/**', // z-samples, z1, z2, etc.
      '.claude/**',
      '.codex/**',
      '.github/chatmodes/**',
      '.agent/**',
      '.agentvibes/**',
      '.kiro/**',
      '.roo/**',
      'test-project-install/**',
      'sample-project/**',
      'tools/template-test-generator/test-scenarios/**',
      'src/modules/*/sub-modules/**',
      '.bundler-temp/**',
      'temp/**',
    ],
  },

  // Base JavaScript recommended rules
  js.configs.recommended,

  // Node.js rules
  ...nodePlugin.configs['flat/mixed-esm-and-cjs'],

  // Unicorn rules (modern best practices)
  unicorn.configs.recommended,

  // YAML linting
  ...yml.configs['flat/recommended'],

  // Place Prettier last to disable conflicting stylistic rules
  eslintConfigPrettier,

  // Project-specific tweaks
  {
    rules: {
      // Allow console for CLI tools in this repo
      'no-console': 'off',
      // Enforce .yaml file extension for consistency
      'yml/file-extension': [
        'error',
        {
          extension: 'yaml',
          caseSensitive: true,
        },
      ],
      // Prefer double quotes in YAML wherever quoting is used, but allow the other to avoid escapes
      'yml/quotes': [
        'error',
        {
          prefer: 'double',
          avoidEscape: true,
        },
      ],
      // Relax some Unicorn rules that are too opinionated for this codebase
      'unicorn/prevent-abbreviations': 'off',
      'unicorn/no-null': 'off',
    },
  },

  // CLI scripts under tools/** and test/**
  {
    files: ['tools/**/*.js', 'tools/**/*.mjs', 'test/**/*.js'],
    rules: {
      // Allow CommonJS patterns for Node CLI scripts
      'unicorn/prefer-module': 'off',
      'unicorn/import-style': 'off',
      'unicorn/no-process-exit': 'off',
      'n/no-process-exit': 'off',
      'unicorn/no-await-expression-member': 'off',
      'unicorn/prefer-top-level-await': 'off',
      // Avoid failing CI on incidental unused vars in internal scripts
      'no-unused-vars': 'off',
      // Reduce style-only churn in internal tools
      'unicorn/prefer-ternary': 'off',
      'unicorn/filename-case': 'off',
      'unicorn/no-array-reduce': 'off',
      'unicorn/no-array-callback-reference': 'off',
      'unicorn/consistent-function-scoping': 'off',
      'n/no-extraneous-require': 'off',
      'n/no-extraneous-import': 'off',
      'n/no-unpublished-require': 'off',
      'n/no-unpublished-import': 'off',
      // Some scripts intentionally use globals provided at runtime
      'no-undef': 'off',
      // Additional relaxed rules for legacy/internal scripts
      'no-useless-catch': 'off',
      'unicorn/prefer-number-properties': 'off',
      'no-unreachable': 'off',
      'unicorn/text-encoding-identifier-case': 'off',
    },
  },

  // ESLint config file should not be checked for publish-related Node rules
  {
    files: ['eslint.config.mjs'],
    rules: {
      'n/no-unpublished-import': 'off',
    },
  },

  // GitHub workflow files in this repo may use empty mapping values
  {
    files: ['.github/workflows/**/*.yaml'],
    rules: {
      'yml/no-empty-mapping-value': 'off',
    },
  },

  // Other GitHub YAML files may intentionally use empty values and reserved filenames
  {
    files: ['.github/**/*.yaml'],
    rules: {
      'yml/no-empty-mapping-value': 'off',
      'unicorn/filename-case': 'off',
    },
  },
];

