  );

  // ============================================================
  // Suite H: Custom threshold = 90 (same scores as A, now FAIL)
  // ============================================================
  console.log(`\n${colors.yellow}Suite H: Custom threshold = 90${colors.reset}\n`);

  const suiteH = computeScore({
